 1→<?php
 2→
 3→namespace App\Http\Controllers;
 4→
 5→use App\Services\AiAnalysisService;
 6→use App\Services\DecryptService;
 7→use Illuminate\Http\Request;
 8→use Illuminate\Support\Facades\Log;
 9→
10→class AiController extends Controller
11→{
12→    /**
13→     * 通用 AI 对话接口，供 oa-server 调用。
14→     * 支持 blocking（返回 JSON）和 streaming（返回 SSE）两种模式。
15→     * 可选：decrypt_config 解密 message 中的加密标记，compress 压缩文本减少 token。
16→     */
17→    public function chat(Request $request): mixed
18→    {
19→        $systemPrompt = $request->input('system_prompt', '');
20→        $message = $request->input('message', '');
21→        $responseMode = $request->input('response_mode', 'blocking');
22→        $history = $request->input('history', []);
23→        $decryptConfig = $request->input('decrypt_config');
24→        $compress = (bool)$request->input('compress', false);
25→
26→        // 解密 message 中的加密标记（##crypt:...#...:crypt##）
27→        // master-api 没有用户 session，通过 decrypt_config.tokens 进行权限校验（与 mail/send-decr 一致）
28→        if (!empty($decryptConfig)) {
29→            $data = ['message' => $message];
30→            $operation = $decryptConfig['operation'] ?? 'response';
31→            $data = DecryptService::app()->decryptData($data, $decryptConfig, $operation);
32→            $message = $data['message'];
33→            // 清理权限不足的解密残留：[E:xxx]密文 → 移除，避免 AI 收到乱码
34→            $message = preg_replace('/\[E:\d+\]\S+/', '', $message);
35→            Log::info('[lbl][0416-AI日报][AiChat] 已解密 message', ['decrypted_len' => mb_strlen($message)]);
36→        }
37→
38→        // 压缩文本：去除 HTML 标签、合并多余空白行，减少 AI token 消耗
39→        if ($compress) {
40→            $message = strip_tags($message);
41→            $message = preg_replace('/\n{3,}/', "\n\n", $message);
42→            $message = preg_replace('/[ \t]+/', ' ', $message);
43→            $message = trim($message);
44→            Log::info('[lbl][0416-AI日报][AiChat] 已压缩 message', ['compressed_len' => mb_strlen($message)]);
45→        }
46→
47→        Log::info('[lbl][0416-AI日报][AiChat][CALL] 收到AI对话请求', [
48→            'response_mode' => $responseMode,
49→            'message_len' => mb_strlen($message),
50→            'prompt_len' => mb_strlen($systemPrompt),
51→            'history_count' => count($history),
52→        ]);
53→
54→        if ($responseMode === 'streaming') {
55→            return response()->stream(function () use ($message, $systemPrompt, $history) {
56→                AiAnalysisService::app()->analyzeStream(
57→                    $message,
58→                    $systemPrompt,
59→                    function (string $chunk) {
60→                        echo 'data: '.json_encode([
61→                            'event' => 'message',
62→                            'answer' => $chunk,
63→                        ], JSON_UNESCAPED_UNICODE).PHP_EOL.PHP_EOL;
64→                        ob_flush();
65→                        flush();
66→                    },
67→                    $history
68→                );
69→                // 结束帧
70→                echo 'data: '.json_encode([
71→                    'event' => 'message_end',
72→                ], JSON_UNESCAPED_UNICODE).PHP_EOL.PHP_EOL;
73→                ob_flush();
74→                flush();
75→            }, 200, [
76→                'Content-Type' => 'text/event-stream',
77→                'Cache-Control' => 'no-cache',
78→                'X-Accel-Buffering' => 'no',
79→            ]);
80→        }
81→
82→        // Blocking mode
83→        $answer = AiAnalysisService::app()->analyze($message, $systemPrompt);
84→
85→        return response()->json([
86→            'error_code' => '0',
87→            'error_msg' => '',
88→            'data' => ['answer' => $answer],
89→        ]);
90→    }
91→}
