  1→<?php
  2→
  3→namespace App\Services;
  4→
  5→use App\Models\OwnerMd;
  6→use App\Models\SfuserMd;
  7→use Exception;
  8→use Illuminate\Http\Client\Response;
  9→use Illuminate\Http\Request;
 10→use Illuminate\Support\Arr;
 11→use Illuminate\Support\Facades\App;
 12→use Illuminate\Support\Facades\Log;
 13→use Illuminate\Support\Facades\Session;
 14→
 15→/**
 16→ * TransferRequestService 用于转发请求到业务后端。
 17→ */
 18→class TransferRequestService
 19→{
 20→    use ServiceTrait;
 21→
 22→    /**
 23→     * 转发请求给后端服务器，同时对请求参数和响应结果做一些处理.
 24→     *
 25→     * @param Request $request 请求
 26→     * @param mixed $action
 27→     * @throws \App\Exceptions\UserException
 28→     * @throws \App\Exceptions\ServerException
 29→     * @throws \App\Exceptions\AuthorizationException
 30→     * @throws \App\Exceptions\CommonException
 31→     * @throws \App\Exceptions\CryptoException
 32→     * @throws \App\Exceptions\ResourceException
 33→     * @return array 请求参数处理后的新的参数
 34→     */
 35→    public function transfer(Request $request, string $action = ''): mixed
 36→    {
 37→        $params = $request->all();
 38→
 39→        // 提取特定的请求参数
 40→        $reservedWords = [
 41→            'decrypt_config', 'encrypt_config', 'update_permission', 'next_replace_filter',
 42→            'hash_filter', 'replace_filter', 'authorize_config', 'intact_columns', 'response_format',
 43→            'ai_analysis_config',
 44→        ];
 45→        foreach ($reservedWords as $word) {
 46→            ${$word} = $params[$word] ?? null;
 47→            unset($params[$word]);
 48→        }
 49→
 50→        // 对请求参数进行加密
 51→        if (!empty($encrypt_config)) {
 52→            if (Arr::isAssoc($encrypt_config)) {
 53→                $encrypt_config = [$encrypt_config];
 54→            }
 55→            foreach ($encrypt_config as $conf) {
 56→                $params = EncryptService::app()->encryptData($params, $conf);
 57→            }
 58→        } else {
 59→            // 分页、版本号、语言控制参数应当默认放行
 60→            $intact_columns = array_merge_index($intact_columns ?? [], ['version_info', 'sys_lang', 'page', 'per_page']);
 61→            // 对所有 intact_columns 之外的属性进行 unset，该字段无需递归处理
 62→            $intact_columns = Arr::wrap($intact_columns);
 63→            $params = Arr::only($params, $intact_columns);
 64→        }
 65→
 66→        // 处理请求参数中“更新权限”的操作
 67→        if (!empty($update_permission)) {
 68→            if (Arr::isAssoc($update_permission)) {
 69→                $update_permission = [$update_permission];
 70→            }
 71→            foreach ($update_permission as $conf) {
 72→                $params = ResourceService::app()->updateResPermission($params, $conf);
 73→            }
 74→        }
 75→
 76→        // 处理请求参数中“哈希筛选”的参数
 77→        if (!empty($hash_filter)) {
 78→            $params = HashFilterService::app()->hashFilter($params, $hash_filter);
 79→        }
 80→
 81→        // 处理请求参数中“替换筛选”的参数
 82→        if (!empty($replace_filter)) {
 83→            $params = ReplaceFilterService::app()->replaceFilter($params, $replace_filter);
 84→        }
 85→
 86→        if (!empty($next_replace_filter)) {
 87→            $params = NextReplaceFilterService::app()->replaceFilter($params, $next_replace_filter);
 88→        }
 89→
 90→        // 处理请求参数中“授权”参数
 91→        if (!empty($authorize_config)) {
 92→            $token = AuthorizeService::app()->generateToken($authorize_config);
 93→            $params['authorized_token'] = $token;
 94→        }
 95→
 96→        // 有些接口是 stream response，这部分请求没办法用通用的 JSON 方式处理，所以这里直接转发，为了避免造成破坏性变更
 97→        // 这里只对部分接口进行特殊处理
 98→        if (!empty($response_format) && $response_format == 'stream') {
 99→            // 如果同时有 ai_analysis_config，需要先拿完整响应再做 AI streaming
100→            if (!empty($ai_analysis_config) && !empty($ai_analysis_config['system_prompt'])) {
101→                $resp = $this->callBackendApi($action ?: $request->path(), $params);
102→                if (!empty($resp['data'])) {
103→                    $respData = &$resp['data'];
104→
105→                    // 解密
106→                    $decrypt_config = empty($respData['decrypt_config']) ? $decrypt_config : array_merge($decrypt_config ?? [], $respData['decrypt_config']);
107→                    if (isset($respData['decrypt_config'])) {
108→                        unset($respData['decrypt_config']);
109→                    }
110→                    if (!empty($decrypt_config)) {
111→                        $respData = DecryptService::app()->decryptData($respData, $decrypt_config, 'response');
112→                    }
113→
114→                    // 提取 AI 输入内容
115→                    $targetField = $ai_analysis_config['target_field'] ?? null;
116→                    $contentForAi = $targetField ? data_get($respData, $targetField, '') : json_encode($respData, JSON_UNESCAPED_UNICODE);
117→                    if (is_array($contentForAi)) {
118→                        $contentForAi = json_encode($contentForAi, JSON_UNESCAPED_UNICODE);
119→                    }
120→
121→                    $systemPrompt = $ai_analysis_config['system_prompt'];
122→                    $history = $ai_analysis_config['history'] ?? [];
123→
124→                    return response()->stream(function () use ($contentForAi, $systemPrompt, $history) {
125→                        AiAnalysisService::app()->analyzeStream(
126→                            $contentForAi,
127→                            $systemPrompt,
128→                            function (string $chunk) {
129→                                echo 'data: '.json_encode([
130→                                    'error_code' => 0,
131→                                    'error_msg' => '',
132→                                    'data' => ['type' => 'chat', 'is_finished' => false, 'content' => $chunk],
133→                                ], JSON_UNESCAPED_UNICODE).PHP_EOL.PHP_EOL;
134→                                ob_flush();
135→                                flush();
136→                            },
137→                            $history
138→                        );
139→                        // 结束帧
140→                        echo 'data: '.json_encode([
141→                            'error_code' => 0,
142→                            'error_msg' => '',
143→                            'data' => ['type' => 'chat', 'is_finished' => true, 'content' => ''],
144→                        ], JSON_UNESCAPED_UNICODE).PHP_EOL.PHP_EOL;
145→                        ob_flush();
146→                        flush();
147→                    }, 200, [
148→                        'Content-Type' => 'text/event-stream',
149→                        'Cache-Control' => 'no-cache',
150→                        'X-Accel-Buffering' => 'no',
151→                    ]);
152→                }
153→            }
154→
155→            // 原有的 stream 透传逻辑不变
156→            $resp = $this->callBackendApi($action ?: $request->path(), $params, true);
157→            return response()->stream(function () use ($resp) {
158→                $body = $resp->toPsrResponse()->getBody();
159→                $content = '';
160→                while (!$body->eof()) {
161→                    $bit = $body->read(1);
162→                    $content .= $bit;
163→                    if (substr($content, -2) == PHP_EOL.PHP_EOL) {
164→                        echo $content;
165→                        ob_flush();
166→                        flush();
167→                        $content = '';
168→                    }
169→                }
170→            }, $resp->status(), array_merge($resp->headers(), ['X-Accel-Buffering' => 'no']));
171→        }
172→
173→        $resp = $this->callBackendApi($action ?: $request->path(), $params);
174→        if (!empty($resp['data'])) {
175→            $respData = &$resp['data'];
176→            // 响应中有 decrypt_config 的话，与请求中的 decrypt_config 合并（相同键名以响应中的为准）
177→            $decrypt_config = empty($respData['decrypt_config']) ? $decrypt_config : array_merge($decrypt_config ?? [], $respData['decrypt_config']);
178→            if (isset($respData['decrypt_config'])) {
179→                unset($respData['decrypt_config']);
180→            }
181→            if (!empty($decrypt_config)) {
182→                $respData = DecryptService::app()->decryptData($respData, $decrypt_config, 'response');
183→            }
184→
185→            // AI 分析（解密之后执行，仅当 ai_analysis_config 存在时）
186→            if (!empty($ai_analysis_config) && !empty($ai_analysis_config['system_prompt'])) {
187→                $targetField = $ai_analysis_config['target_field'] ?? null;
188→                $outputField = $ai_analysis_config['output_field'] ?? 'ai_analysis';
189→                $contentForAi = $targetField ? data_get($respData, $targetField, '') : json_encode($respData, JSON_UNESCAPED_UNICODE);
190→
191→                if (is_array($contentForAi)) {
192→                    $contentForAi = json_encode($contentForAi, JSON_UNESCAPED_UNICODE);
193→                }
194→
195→                $aiResult = AiAnalysisService::app()->analyze(
196→                    $contentForAi,
197→                    $ai_analysis_config['system_prompt']
198→                );
199→                data_set($respData, $outputField, $aiResult);
200→            }
201→        }
202→
203→        return $resp;
204→    }
205→
206→    public function transferWithoutEncryptionProcess(Request $request, string $action = '', bool $retOrigResp = false): mixed
207→    {
208→        // 该请求不会做任何涉及到加解密的操作，直接转发即可，基于对三方的不信任，我们也不提供 hash/replace 之类的筛选
209→        $params = $request->all();
210→        $user = auth()->user()->getAuthIdentifier();
211→        $sfuser = SfuserMd::find($user);
212→        $params['sfuser_info'] = [
213→            'id' => $sfuser->id,
214→            'is_admin' => $sfuser->is_admin,
215→            'auth_source' => SfuserMd::AUTH_SOURCE_TOKEN,
216→            // 权限也一并不传递，尽力约束三方应用可以执行的操作
217→            'permissions' => [],
218→            'res_attrs' => [],
219→        ];
220→
221→        $fallbackSite = $sfuser->site;
222→        $site = $request->input('sys_site', $fallbackSite);
223→        // 如果 site 非法，使用我们默认的 site
224→        if (!in_array(strtoupper($site), config('my_sites.active_backend_sites'))) {
225→            $site = $fallbackSite;
226→        }
227→        SiteService::app()->setSite($site);
228→        $params['sys_lang'] = App::currentLocale();
229→        // 转发客户端 IP，以便后端某些接口针对 ip 进行过滤或者限流
230→        $params['client_ip'] = \Illuminate\Support\Facades\Request::ip();
231→
232→        $uri = $action ?: $request->path();
233→        if ($retOrigResp) {
234→            return ApiService::appWith('backend')->allowError()->sendRequest($uri, $params, ['stream' => true], true);
235→        }
236→
237→        return ApiService::appWith('backend')->allowError()->sendRequest($uri, $params);
238→    }
239→
240→    /**
241→     * 调用后端接口。
242→     *
243→     * @param string $uri 请求地址
244→     * @param array $params 请求参数
245→     * @return array|Response 后端返回值
246→     */
247→    protected function callBackendApi(string $uri, array $params, bool $retOrigResp = false): array|Response
248→    {
249→        $params['sfuser_info'] = Arr::only(Session::get('sfuser', []), ['id', 'is_admin', 'auth_source']);
250→        $owner = null;
251→        try {
252→            $owner = OwnerMd::find();
253→        } catch (Exception $e) {
254→            Log::error('get perm error', [
255→                'e' => $e,
256→            ]);
257→        }
258→
259→        // 为了减少转发的请求的 payload 的大小，员工端不转发 permissions/res_attrs，针对员工端请求，后端暂时不需要通过权限过滤数据
260→        $authType = App::get('sys_auth_type');
261→        $params['sfuser_info']['permissions'] = (isset($owner) && $authType != 'staff') ? $owner->getPermissions() : [];
262→        $params['sfuser_info']['res_attrs'] = (isset($owner) && $authType != 'staff') ? $owner->getResAttrs() : [];
263→
264→        // 将支持的语言也一并转发到后端，以便支持本地化选项
265→        $params['sys_lang'] = App::currentLocale();
266→        // 转发客户端 IP，以便后端某些接口针对 ip 进行过滤或者限流
267→        $params['client_ip'] = \Illuminate\Support\Facades\Request::ip();
268→
269→        if ($retOrigResp) {
270→            return ApiService::appWith('backend')->allowError()->sendRequest($uri, $params, ['stream' => true, 'timeout' => 1200], true);
271→        }
272→
273→        return ApiService::appWith('backend')->allowError()->sendRequest($uri, $params);
274→    }
275→}
