  3→namespace App\Service;
  4→
  5→use Illuminate\Support\Facades\Log;
  6→
  7→/**
  8→ * AI 流式调用 oa-core 的公共逻辑，供 DailyReportAiController 和 DailyReportAiEmailController 复用.
  9→ */
 10→class AiStreamService
 11→{
 12→    /**
 13→     * 调用 oa-core ai/chat 接口（streaming），通过回调逐 chunk 输出.
 14→     *
 15→     * @param string $message 发给 AI 的用户消息
 16→     * @param string $systemPrompt 系统 Prompt
 17→     * @param callable $onChunk fn(string $chunk): void 每个 chunk 的回调
 18→     * @param array $extraParams 额外参数（history, decrypt_config, compress 等）
 19→     * @return array ['full_reply' => string, 'http_code' => int, 'curl_error' => string]
 20→     */
 21→    public static function streamFromCore(
 22→        string $message,
 23→        string $systemPrompt,
 24→        callable $onChunk,
 25→        array $extraParams = []
 26→    ): array {
 27→        $coreBaseUrl = rtrim(config('my_project.core_url', ''), '/');
 28→        $aiUrl = $coreBaseUrl.'/master-api/ai/chat';
 29→        $coreApiSecret = config('my_project.core_api_secret');
 30→
 31→        $requestParams = [
 32→            'system_prompt' => $systemPrompt ?: ' ',
 33→            'message' => $message,
 34→            'response_mode' => 'streaming',
 35→            'sys_site' => config('my_project.site_key'),
 36→        ];
 37→
 38→        // 合并额外参数（history, decrypt_config, compress 等）
 39→        foreach (['history', 'decrypt_config', 'compress'] as $key) {
 40→            if (isset($extraParams[$key])) {
 41→                $requestParams[$key] = $extraParams[$key];
 42→            }
 43→        }
 44→
 45→        $requestParams['sign'] = get_sign(['api_secret' => $coreApiSecret] + $requestParams, true);
 46→        $payload = json_encode($requestParams, JSON_UNESCAPED_UNICODE);
 47→
 48→        Log::info('[lbl][0416-AI日报][AiStream] 发给oa-core的请求', [
 49→            'url' => $aiUrl,
 50→            'system_prompt_len' => mb_strlen($systemPrompt),
 51→            'message_len' => mb_strlen($message),
 52→            'has_decrypt' => isset($extraParams['decrypt_config']),
 53→            'compress' => $extraParams['compress'] ?? false,
 54→        ]);
 55→
 56→        $fullReply = '';
 57→        $buffer = '';
 58→
 59→        $ch = curl_init($aiUrl);
 60→        curl_setopt_array($ch, [
 61→            CURLOPT_POST => true,
 62→            CURLOPT_POSTFIELDS => $payload,
 63→            CURLOPT_HTTPHEADER => ['Content-Type: application/json'],
 64→            CURLOPT_RETURNTRANSFER => false,
 65→            CURLOPT_TIMEOUT => 300,
 66→            CURLOPT_WRITEFUNCTION => function ($curl, $data) use (&$fullReply, &$buffer, $onChunk) {
 67→                $buffer .= $data;
 68→
 69→                while (($pos = strpos($buffer, "\n")) !== false) {
 70→                    $line = rtrim(substr($buffer, 0, $pos), "\r");
 71→                    $buffer = substr($buffer, $pos + 1);
 72→
 73→                    if (!str_starts_with($line, 'data: ')) {
 74→                        continue;
 75→                    }
 76→
 77→                    $decoded = json_decode(substr($line, 6), true);
 78→                    if (!is_array($decoded)) {
 79→                        continue;
 80→                    }
 81→
 82→                    $event = $decoded['event'] ?? '';
 83→                    if ($event === 'message') {
 84→                        $chunk = $decoded['answer'] ?? '';
 85→                        if ($chunk !== '') {
 86→                            $fullReply .= $chunk;
 87→                            $onChunk($chunk);
 88→                        }
 89→                    }
 90→                }
 91→
 92→                return strlen($data);
 93→            },
 94→        ]);
 95→
 96→        $success = curl_exec($ch);
 97→        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
 98→        $curlError = $success ? '' : curl_error($ch);
 99→        curl_close($ch);
100→
101→        Log::info('[lbl][0416-AI日报][AiStream] done', [
102→            'http_code' => $httpCode,
103→            'curl_error' => $curlError,
104→            'reply_len' => mb_strlen($fullReply),
105→        ]);
106→
107→        return [
108→            'full_reply' => $fullReply,
109→            'http_code' => $httpCode,
110→            'curl_error' => $curlError,
111→        ];
112→    }
113→}
