460→    public function extractSlots(Request $request): JsonResponse
461→    {
462→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
463→        if (!$this->inWhitelist($sfuserId)) {
464→            return $this->responseJsonFail('无权限');
465→        }
466→
467→        $message = $request->input('message');
468→        $conversationId = $request->input('conversation_id', '');
469→        $availableGroups = $request->input('available_groups', []);
470→        $availableMembers = $request->input('available_members', []);
471→        $previousContext = $request->input('previous_context');
472→        $hasExistingContext = $request->boolean('has_existing_context', false);
473→
474→        // 将可用分组和成员列表格式化为 prompt 中的列表
475→        $groupList = !empty($availableGroups)
476→            ? implode("\n", array_map(fn ($g) => "   - {$g}", $availableGroups))
477→            : '   - （无可用分组）';
478→        $memberList = !empty($availableMembers)
479→            ? implode('、', $availableMembers)
480→            : '（无可用成员列表）';
481→        // 上次查询上下文：首次查询时为"无"，续查时包含上次的成员和周期
482→        $prevCtx = '无（首次查询）';
483→        if (!empty($previousContext)) {
484→            $prevMembers = implode('、', $previousContext['members'] ?? []);
485→            $prevType = ($previousContext['member_type'] ?? '') === 'group' ? '分组' : '成员';
486→            $prevPeriod = ($previousContext['period_start'] ?? '').' ~ '.($previousContext['period_end'] ?? '');
487→            $prevCtx = "上次查询{$prevType}：{$prevMembers}，周期：{$prevPeriod}";
488→        }
489→        $hasContextLabel = $hasExistingContext ? '是' : '否';
490→        $systemPrompt = sprintf(self::SLOT_EXTRACTION_PROMPT, $hasContextLabel, $groupList, $memberList, now()->toDateString(), $prevCtx);
491→
492→        \Log::info('[lbl][0416-AI日报][AiSlots] request', [
493→            'sfuser_id' => $sfuserId,
494→            'message' => $message,
495→            'previous_context' => $previousContext,
496→            'available_groups' => $availableGroups,
497→            'member_count' => count($availableMembers),
498→        ]);
499→
500→        // 调用 oa-core AI 接口（替代 Dify）
501→        $corePayload = [
502→            'system_prompt' => $systemPrompt,
503→            'message' => $message,
504→            'response_mode' => 'blocking',
505→        ];
506→        \Log::info('[lbl][0416-AI日报][extractSlots] 发给oa-core的请求参数', [
507→            'url' => 'master-api/ai/chat',
508→            'system_prompt_preview' => mb_substr($corePayload['system_prompt'] ?? '', 0, 100),
509→            'message_preview' => mb_substr($corePayload['message'] ?? '', 0, 100),
510→            'response_mode' => $corePayload['response_mode'] ?? '',
511→        ]);
512→        try {
513→            $aiResponse = \App\Lib\Facade\CoreApiLib::sendRequest('master-api/ai/chat', $corePayload);
514→        } catch (\Throwable $e) {
515→            \Log::error('[lbl][0416-AI日报][AiSlots] oa-core AI request failed', ['error' => $e->getMessage()]);
516→            return $this->responseJsonFail('AI 接口请求失败：'.$e->getMessage());
517→        }
518→
519→        $answer = $aiResponse['data']['answer'] ?? '';
520→
521→        \Log::info('[lbl][0416-AI日报][AiSlots] response', [
522→            'sfuser_id' => $sfuserId,
523→            'answer_raw' => mb_substr($answer, 0, 1000),
524→        ]);
525→
526→        // 解析 LLM 输出的 JSON
527→        $slots = $this->parseSlotJson($answer);
528→
529→        \Log::info('[lbl][0416-AI日报][AiSlots] parsed', [
530→            'sfuser_id' => $sfuserId,
531→            'intent' => $slots['intent'],
532→            'slots_complete' => $slots['slots_complete'],
533→            'member_type' => $slots['member_type'],
534→            'members' => $slots['members'],
535→            'period' => $slots['period_start'].' ~ '.$slots['period_end'],
536→            'reply' => mb_substr($slots['reply'], 0, 200),
537→        ]);
538→
539→        return $this->responseJsonSuccess([
540→            'intent' => $slots['intent'],
541→            'slots_complete' => $slots['slots_complete'],
542→            'members' => $slots['members'],
543→            'member_type' => $slots['member_type'],
544→            'period_start' => $slots['period_start'],
545→            'period_end' => $slots['period_end'],
546→            'period_raw' => $slots['period_raw'],
547→            'reply' => $slots['reply'],
548→            'conversation_id' => '',
549→        ]);
550→    }
