552→    // ----------------------------------------------------------------
553→    // 发送消息（SSE 流式）
554→    // ----------------------------------------------------------------
555→
556→    public function ask(Request $request): StreamedResponse
557→    {
558→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
559→        if (!$this->inWhitelist($sfuserId)) {
560→            return $this->sseError('无权限');
561→        }
562→        $roleId = $request->input('role_id');
563→        $sessionId = $request->input('session_id');
564→        $message = $request->input('message');
565→        $reportContext = $request->input('report_context', '');
566→        $reportContextRaw = $request->input('report_context_raw', '');
567→        $history = $request->input('history', []);
568→
569→        // 解压 report_context（前端 gzip+base64 压缩后以 "gz:" 前缀标识）
570→        if (str_starts_with($reportContext, 'gz:')) {
571→            $decoded = base64_decode(substr($reportContext, 3), true);
572→            $reportContext = $decoded !== false ? (gzdecode($decoded) ?: $reportContext) : $reportContext;
573→        }
574→        // 去除多余空白（连续空行压缩为单空行），减少发给 AI 的 token
575→        $reportContext = preg_replace('/\n{3,}/', "\n\n", trim($reportContext));
576→        \Log::info('[lbl][0416-AI日报][AiAsk] report_context size', [
577→            'bytes' => strlen($reportContext),
578→            'chars' => mb_strlen($reportContext),
579→        ]);
580→
581→        // 校验角色归属
582→        $role = DB::table('daily_report_ai_roles')
583→            ->where('id', $roleId)
584→            ->where('sfuser_id', $sfuserId)
585→            ->whereNull('deleted_at')
586→            ->first();
587→
588→        if (!$role) {
589→            return $this->sseError('角色不存在');
590→        }
591→
592→        // 创建或复用会话
593→        if (!$sessionId) {
594→            $title = mb_substr($message, 0, 20);
595→            $sessionId = DB::table('daily_report_ai_sessions')->insertGetId([
596→                'sfuser_id' => $sfuserId,
597→                'role_id' => $roleId,
598→                'title' => $title,
599→                'created_at' => now(),
600→                'updated_at' => now(),
601→            ]);
602→        } else {
603→            $sessionRow = DB::table('daily_report_ai_sessions')
604→                ->where('id', $sessionId)
605→                ->where('sfuser_id', $sfuserId)
606→                ->whereNull('deleted_at')
607→                ->first();
608→            if (!$sessionRow) {
609→                return $this->sseError('会话不存在');
610→            }
611→        }
612→
613→        // 解压 report_context_raw（与 report_context 相同的 gzip+base64 压缩格式）
614→        if (str_starts_with($reportContextRaw, 'gz:')) {
615→            $decoded = base64_decode(substr($reportContextRaw, 3), true);
616→            $reportContextRaw = $decoded !== false ? (gzdecode($decoded) ?: $reportContextRaw) : $reportContextRaw;
617→        }
618→
619→        // 保存同步日报上下文（如果有）—— 优先存原始 HTML，便于页面回显
620→        $contextToStore = !empty($reportContextRaw) ? $reportContextRaw : $reportContext;
621→        if (!empty($contextToStore)) {
622→            DB::table('daily_report_ai_messages')->insert([
623→                'session_id' => $sessionId,
624→                'role' => 'context',
625→                'content' => $contextToStore,
626→                'created_at' => now(),
627→            ]);
628→        }
629→
630→        // 保存用户消息
631→        DB::table('daily_report_ai_messages')->insert([
632→            'session_id' => $sessionId,
633→            'role' => 'user',
634→            'content' => $message,
635→            'created_at' => now(),
636→        ]);
637→
638→        // 更新会话时间
639→        DB::table('daily_report_ai_sessions')
640→            ->where('id', $sessionId)
641→            ->update(['updated_at' => now()]);
642→
643→        $capturedSessionId = $sessionId;
644→        $systemPrompt = $role->system_prompt;
645→
646→        return response()->stream(function () use (
647→            $message,
648→            $reportContext,
649→            $systemPrompt,
650→            $capturedSessionId,
651→            $history
652→        ) {
653→            // 客户端断开后继续执行，确保 AI 回答能写入数据库
654→            ignore_user_abort(true);
655→
656→            // 首帧：发送 session_id
657→            $this->echoData(0, '', ['type' => 'session_id', 'session_id' => $capturedSessionId]);
658→
659→            // 构建发送给 AI 的内容
660→            $queryParts = [];
661→            if (!empty($reportContext)) {
662→                $queryParts[] = "[日报数据]\n{$reportContext}";
663→            }
664→            $queryParts[] = $message;
665→            $query = implode("\n\n---\n\n", $queryParts);
666→
667→            \Log::info('[lbl][0416-AI日报][AiAsk] request', [
668→                'session' => $capturedSessionId,
669→                'query_len' => mb_strlen($query),
670→            ]);
671→
672→            // 通过 AiStreamService 调用 oa-core AI 接口进行流式输出
673→            $result = AiStreamService::streamFromCore(
674→                $query,
675→                $systemPrompt,
676→                function (string $chunk) {
677→                    $this->echoData(0, '', ['type' => 'chat', 'is_finished' => false, 'finish_reason' => '', 'content' => $chunk]);
678→                },
679→                !empty($history) ? ['history' => $history] : []
680→            );
681→
682→            $fullReply = $result['full_reply'];
683→            $curlError = $result['curl_error'];
684→
685→            if ($curlError || empty($fullReply)) {
686→                $errMsg = $curlError ? 'AI 接口请求失败，请稍后重试' : 'AI 未返回任何内容，请稍后重试';
687→                try {
688→                    DB::reconnect();
689→                    DB::table('daily_report_ai_messages')->insert([
690→                        'session_id' => $capturedSessionId,
691→                        'role' => 'assistant',
692→                        'content' => $errMsg,
693→                        'created_at' => now(),
694→                    ]);
695→                } catch (\Throwable $e) {
696→                    \Log::error('[lbl][0416-AI日报][AiAsk] save error reply failed', ['session' => $capturedSessionId, 'error' => $e->getMessage()]);
697→                }
698→                $this->echoData(1, $errMsg, []);
699→                return;
700→            }
701→
702→            // 保存 AI 回答
703→            try {
704→                DB::reconnect();
705→                DB::statement('SET NAMES utf8mb4 COLLATE utf8mb4_unicode_ci');
706→                DB::table('daily_report_ai_messages')->insert([
707→                    'session_id' => $capturedSessionId,
708→                    'role' => 'assistant',
709→                    'content' => $fullReply,
710→                    'created_at' => now(),
711→                ]);
712→                \Log::info('[lbl][0416-AI日报][AiAsk] db save ok', ['session' => $capturedSessionId]);
713→            } catch (\Throwable $e) {
714→                \Log::error('[lbl][0416-AI日报][AiAsk] db save failed', ['session' => $capturedSessionId, 'error' => $e->getMessage()]);
715→            }
716→
717→            $this->echoData(0, '', ['type' => 'chat', 'is_finished' => true, 'finish_reason' => 'stop', 'content' => '']);
718→        }, 200, [
719→            'Content-Type' => 'text/event-stream',
720→            'Cache-Control' => 'no-cache',
721→            'X-Accel-Buffering' => 'no',
722→        ]);
723→    }
724→
725→    /**
726→     * 从 LLM 输出中解析槽位 JSON，兼容 markdown 代码块包裹.
727→     */
728→    private function parseSlotJson(string $text): array
729→    {
730→        $fallback = [
731→            'intent' => 'new_query',
732→            'slots_complete' => false,
733→            'members' => [],
734→            'member_type' => '',
735→            'period_start' => '',
736→            'period_end' => '',
737→            'period_raw' => '',
738→            'reply' => '抱歉没理解你的意思，请告诉我你想查哪个分组或具体成员的日报，以及查哪个时间段？',
739→        ];
740→
741→        if (!preg_match('/\{[\s\S]*\}/', $text, $matches)) {
742→            \Log::warning('[lbl][0416-AI日报][AiSlots] no JSON found in answer', ['text' => mb_substr($text, 0, 500)]);
743→            return $fallback;
744→        }
745→
746→        $data = json_decode($matches[0], true);
747→        if (!is_array($data)) {
748→            \Log::warning('[lbl][0416-AI日报][AiSlots] JSON parse failed', ['text' => mb_substr($matches[0], 0, 500)]);
749→            return $fallback;
750→        }
751→
752→        return [
753→            'intent' => $data['intent'] ?? 'new_query',
754→            'slots_complete' => !empty($data['slots_complete']),
755→            'members' => $data['members'] ?? [],
756→            'member_type' => $data['member_type'] ?? '',
757→            'period_start' => $data['period_start'] ?? '',
758→            'period_end' => $data['period_end'] ?? '',
759→            'period_raw' => $data['period_raw'] ?? '',
760→            'reply' => $data['reply'] ?? '',
761→        ];
762→    }
