764→    private function inWhitelist(int $sfuserId): bool
765→    {
766→        $setting = OaSetting::where('type', 'daily_report_ai')->select('ids', 'is_on')->first();
767→        if (!$setting || !$setting->is_on) {
768→            return false;
769→        }
770→        return in_array($sfuserId, $setting->ids ?? []);
771→    }
