 13→
 14→class DailyReportAiEmailJob extends MyJob
 15→{
 16→    public function handle(): bool
 17→    {
 18→        $now = now();
 19→        $currentTime = $now->format('H:i');
 20→        $currentDayOfWeek = $now->dayOfWeekIso; // 1=Monday, 7=Sunday
 21→        $currentDayOfMonth = $now->day;
 22→
 23→        info("[lbl][0416-AI日报][AiEmailJob] handle started, currentTime={$currentTime}, dayOfWeek={$currentDayOfWeek}, dayOfMonth={$currentDayOfMonth}");
 24→
 25→        $tasks = DB::table('daily_report_ai_email_tasks')
 26→            ->where('is_on', 1)
 27→            ->whereNull('deleted_at')
 28→            ->where('send_time', $currentTime)
 29→            ->get();
 30→
 31→        if ($tasks->isEmpty()) {
 32→            info("[lbl][0416-AI日报][AiEmailJob] no matching tasks for time={$currentTime}, skip");
 33→            return true;
 34→        }
 35→
 36→        info("[lbl][0416-AI日报][AiEmailJob] found {$tasks->count()} task(s) for time={$currentTime}");
 37→
 38→        foreach ($tasks as $task) {
 39→            if (!$this->shouldSendNow($task, $currentDayOfWeek, $currentDayOfMonth)) {
 40→                continue;
 41→            }
 42→
 43→            try {
 44→                $this->processTask($task);
 45→            } catch (\Throwable $e) {
 46→                info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} failed: {$e->getMessage()}".$e->getTraceAsString());
 47→            }
 48→        }
 49→
 50→        info('[lbl][0416-AI日报][AiEmailJob] finished');
 51→        return true;
 52→    }
 53→
 54→    private function shouldSendNow(object $task, int $dayOfWeek, int $dayOfMonth): bool
 55→    {
 56→        $sendDay = (int)($task->send_day ?? 1);
 57→
 58→        return match ($task->send_cycle) {
 59→            'daily' => true,
 60→            'weekly' => $dayOfWeek === $sendDay,
 61→            'monthly' => $this->isMonthlyMatch($sendDay, $dayOfMonth),
 62→            default => false,
 63→        };
 64→    }
 65→
 66→    /**
 67→     * 月度匹配：如果设定日超过当月天数，则在当月最后一天触发.
 68→     */
 69→    private function isMonthlyMatch(int $sendDay, int $dayOfMonth): bool
 70→    {
 71→        $lastDayOfMonth = (int)now()->endOfMonth()->day;
 72→        $effectiveDay = min($sendDay, $lastDayOfMonth);
 73→
 74→        return $dayOfMonth === $effectiveDay;
 75→    }
 76→
 77→    private function processTask(object $task): void
 78→    {
 79→        $sfuserId = $task->sfuser_id;
 80→
 81→        // 读取邮箱配置
 82→        $mc = MailConfig::where('type', "daily_report_{$sfuserId}")->first();
 83→        if (!$mc || empty(Arr::get($mc->config, 'to_email'))) {
 84→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no email config, skip");
 85→            return;
 86→        }
 87→
 88→        $toEmails = Arr::get($mc->config, 'to_email');
 89→        $sfuserToken = Arr::get($mc->config, 'sfuser_authorized_token', '');
 90→        if (!$sfuserToken) {
 91→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no sfuser_token, skip");
 92→            return;
 93→        }
 94→
 95→        // 确定日报日期范围
 96→        [$startDate, $endDate] = $this->getDateRange($task->report_range);
 97→
 98→        // 拉取该用户能看到日报的全部员工（维度只决定分组方式）
 99→        $dailyService = app(DailyReportService::class);
100→        $subordinates = $dailyService->getSubordinates($sfuserId);
101→        // group_users 是二维数组 [groupId => [userId, ...]]，需要 flatten
102→        $groupUserIds = [];
103→        foreach ($subordinates['group_users'] as $userIds) {
104→            $groupUserIds = array_merge($groupUserIds, $userIds);
105→        }
106→        $targetUserIds = array_unique(array_merge(
107→            $subordinates['direct_subordinates'],
108→            $subordinates['depart_subordinates'],
109→            $subordinates['other_subordinates'],
110→            $subordinates['focus_users'],
111→            $groupUserIds
112→        ));
113→
114→        if (empty($targetUserIds)) {
115→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no visible users, skip");
116→            return;
117→        }
118→
119→        // 拉取日报数据
120→        $data = $dailyService->getOthersDailyReportListEnable(
121→            $startDate,
122→            $endDate,
123→            $sfuserId,
124→            $targetUserIds,
125→            10000
126→        );
127→
128→        if (empty($data) || empty($data['reports']) || empty($data['reports']['report_list'])) {
129→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no report data, skip");
130→            return;
131→        }
132→
133→        $reportList = $data['reports']['report_list'];
134→
135→        // 收集所有日报涉及的 sfuser_id
136→        $reportSfuserIds = array_unique(array_column($reportList, 'sfuser_id'));
137→
138→        // 查询分组信息：按部门需要 department_id + department_name，按直接主管需要 direct_supervisor_id + direct_supervisor_nickname
139→        $sfuserGroupMap = $this->buildGroupMap($reportSfuserIds, $task->dimension);
140→
141→        // 按维度分组日报
142→        $grouped = [];
143→        foreach ($reportList as $report) {
144→            $uid = $report['sfuser_id'];
145→            $groupKey = $sfuserGroupMap[$uid]['key'] ?? 'unknown';
146→            $grouped[$groupKey]['name'] = $sfuserGroupMap[$uid]['name'] ?? '';
147→            $grouped[$groupKey]['reports'][] = $report;
148→        }
149→
150→        info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} dimension={$task->dimension}, groups=".count($grouped));
151→
152→        // 每个分组独立发送一封邮件，各自独立 AI 分析
153→        foreach ($grouped as $groupKey => $group) {
154→            $groupName = $group['name'];
155→            $reports = $group['reports'];
156→
157→            $dimensionLabel = $task->dimension === 'direct_manager' ? '直属主管' : '部门';
158→            $groupNameMarked = EncryptService::app()->markEncrString($groupName);
159→            // 在日报内容前加上分组上下文，解密后 AI 能识别
160→            $content = "<p><b>{$dimensionLabel}：{$groupNameMarked}</b></p>\n";
161→            $no = 0;
162→            foreach ($reports as $report) {
163→                $nickname = $report['data']['nickname'] ?? '';
164→                if (empty($nickname)) {
165→                    continue;
166→                }
167→                $nickname = EncryptService::app()->markEncrString(e($nickname));
168→                $reportContent = EncryptService::app()->markEncrString($report['content']);
169→                ++$no;
170→                $content .= '<p><b>'.$no.'、 '.$nickname.'</b></p>';
171→                $content .= '<div style="border:1px solid #eee;padding:8px;margin-bottom:12px;">'.$reportContent.'</div>';
172→            }
173→
174→            if ($no === 0) {
175→                continue;
176→            }
177→
178→            $subject = "【{$startDate}】 {$task->name}（{$dimensionLabel}：{$groupNameMarked}）- 智能日报";
179→
180→            $params = [
181→                'decrypt_config' => [
182→                    'obj' => '$this',
183→                    'decrypt_columns' => [],
184→                    'partly_decrypt_columns' => ['content', 'subject'],
185→                ],
186→                'receivers' => [[
187→                    'type' => 'token',
188→                    'tokens' => [$sfuserToken],
189→                    'filter' => 'emails',
190→                    'filter_map' => ['emails' => $toEmails],
191→                ]],
192→                'content' => $content,
193→                'subject' => $subject,
194→                'ai_analysis_config' => [
195→                    'system_prompt' => $task->system_prompt,
196→                    'compress' => true,
197→                ],
198→            ];
199→
200→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} sending group={$groupName}({$no}人) to ".implode(',', $toEmails));
201→            CoreApiLib::sendRequest('master-api/mail/send-decr', $params);
202→        }
203→
204→        info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} all groups sent");
205→    }
206→
207→    /**
208→     * 根据维度构建 sfuser_id => ['key' => 分组键, 'name' => 分组名] 的映射.
209→     */
210→    private function buildGroupMap(array $sfuserIds, string $dimension): array
211→    {
212→        if (empty($sfuserIds)) {
213→            return [];
214→        }
215→
216→        $map = [];
217→
218→        if ($dimension === 'direct_manager') {
219→            // 按直接主管分组
220→            $users = Sfuser::whereIn('id', $sfuserIds)
221→                ->select('id', 'direct_supervisor_id', 'direct_supervisor_nickname')
222→                ->get();
223→
224→            foreach ($users as $user) {
225→                $managerId = $user->direct_supervisor_id ?: 0;
226→                $managerName = $user->direct_supervisor_nickname ?: '无直接主管';
227→                $map[$user->id] = [
228→                    'key' => "mgr_{$managerId}",
229→                    'name' => $managerName,
230→                ];
231→            }
232→        } else {
233→            // 按部门分组
234→            $users = Sfuser::whereIn('id', $sfuserIds)
235→                ->select('id', 'department_id')
236→                ->get();
237→
238→            // 批量查部门名称
239→            $deptIds = $users->pluck('department_id')->filter()->unique()->values()->toArray();
240→            $deptNames = [];
241→            if (!empty($deptIds)) {
242→                $deptNames = DB::table('job_departments')
243→                    ->whereIn('department_id', $deptIds)
244→                    ->pluck('department_name', 'department_id')
245→                    ->toArray();
246→            }
247→
248→            foreach ($users as $user) {
249→                $deptId = $user->department_id ?: 0;
250→                $deptName = $deptNames[$deptId] ?? '未分配部门';
251→                $map[$user->id] = [
252→                    'key' => "dept_{$deptId}",
253→                    'name' => $deptName,
254→                ];
255→            }
256→        }
257→
258→        return $map;
259→    }
260→
261→    private function getDateRange(string $reportRange): array
262→    {
263→        $today = now()->toDateString();
264→        return match ($reportRange) {
265→            'last_3_days' => [now()->subDays(2)->toDateString(), $today],
266→            'last_7_days' => [now()->subDays(6)->toDateString(), $today],
267→            default => [$today, $today],
268→        };
269→    }
270→}
