 37→
 38→    /**
 39→     * Streaming 模式：调用 AI，通过回调逐 chunk 输出。
 40→     */
 41→    public function analyzeStream(string $content, string $systemPrompt, callable $onChunk, array $history = []): string
 42→    {
 43→        $useDify = (bool)config('vertex_ai.mock');
 44→
 45→        Log::info('[lbl][0416-AI日报][AiAnalysis][CALL] streaming request', [
 46→            'content_len' => mb_strlen($content),
 47→            'content_preview' => mb_substr($content, 0, 100),
