 64→
 65→    // ----------------------------------------------------------------
 66→    // Dify 接口（mock=true 时使用）
 67→    // ----------------------------------------------------------------
 68→
 69→    /**
 70→     * Dify Blocking 模式。
 71→     */
 72→    private function analyzeDify(string $content, string $systemPrompt): string
 73→    {
 74→        $difyBaseUrl = config('vertex_ai.dify_url');
 75→        $difyKey = config('vertex_ai.dify_key');
 76→
 77→        if (empty($difyBaseUrl) || empty($difyKey)) {
 78→            Log::error('[lbl][0416-AI日报][AiAnalysis][Dify] dify_url or dify_key not configured');
 79→            return '';
 80→        }
 81→
 82→        $difyUrl = rtrim($difyBaseUrl, '/').'/chat-messages';
 83→
 84→        $payload = json_encode([
 85→            'inputs' => ['system_prompt' => $systemPrompt ?: ' '],
 86→            'query' => $content,
 87→            'response_mode' => 'blocking',
 88→            'conversation_id' => '',
 89→            'user' => 'oa-ai-chat',
 90→        ], JSON_UNESCAPED_UNICODE);
 91→
 92→        Log::info('[lbl][0416-AI日报][AiAnalysis][Dify][CALL] blocking 请求 Dify', [
 93→            'url' => $difyUrl,
 94→            'query_len' => mb_strlen($content),
 95→            'prompt_len' => mb_strlen($systemPrompt),
 96→        ]);
 97→
 98→        $ch = curl_init($difyUrl);
 99→        curl_setopt_array($ch, [
100→            CURLOPT_POST => true,
101→            CURLOPT_POSTFIELDS => $payload,
102→            CURLOPT_HTTPHEADER => ['Content-Type: application/json', 'Authorization: Bearer '.$difyKey],
103→            CURLOPT_RETURNTRANSFER => true,
104→            CURLOPT_TIMEOUT => 120,
105→        ]);
106→
107→        $response = curl_exec($ch);
108→        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
109→        $curlError = $response === false ? curl_error($ch) : '';
110→        curl_close($ch);
111→
112→        if ($curlError) {
113→            Log::error('[lbl][0416-AI日报][AiAnalysis][Dify] curl error', ['url' => $difyUrl, 'error' => $curlError]);
114→            return '';
115→        }
116→
117→        $result = json_decode($response, true);
118→        if (!is_array($result)) {
119→            Log::error('[lbl][0416-AI日报][AiAnalysis][Dify] invalid response', ['http_code' => $httpCode, 'raw' => mb_substr($response, 0, 1000)]);
120→            return '';
121→        }
122→
123→        // Dify 错误响应：有 message 但无 answer
124→        if (isset($result['message']) && !isset($result['answer'])) {
125→            Log::error('[lbl][0416-AI日报][AiAnalysis][Dify] error', ['http_code' => $httpCode, 'result' => $result]);
126→            return '';
127→        }
128→
129→        $answer = $result['answer'] ?? '';
130→        Log::info('[lbl][0416-AI日报][AiAnalysis][Dify] blocking done', ['http_code' => $httpCode, 'answer_len' => mb_strlen($answer)]);
131→
132→        return $answer;
133→    }
134→
135→    /**
136→     * Dify Streaming 模式。
137→     */
138→    private function analyzeStreamDify(string $content, string $systemPrompt, callable $onChunk): string
139→    {
140→        $difyBaseUrl = config('vertex_ai.dify_url');
141→        $difyKey = config('vertex_ai.dify_key');
142→
143→        if (empty($difyBaseUrl) || empty($difyKey)) {
144→            Log::error('[lbl][0416-AI日报][AiAnalysis][Dify] dify_url or dify_key not configured');
145→            return '';
146→        }
147→
148→        $difyUrl = rtrim($difyBaseUrl, '/').'/chat-messages';
149→
150→        $payload = json_encode([
151→            'inputs' => ['system_prompt' => $systemPrompt ?: ' '],
152→            'query' => $content,
153→            'response_mode' => 'streaming',
154→            'conversation_id' => '',
155→            'user' => 'oa-ai-chat',
156→        ], JSON_UNESCAPED_UNICODE);
157→
158→        Log::info('[lbl][0416-AI日报][AiAnalysis][Dify][CALL] streaming 请求 Dify', [
159→            'url' => $difyUrl,
160→            'query_len' => mb_strlen($content),
161→            'prompt_len' => mb_strlen($systemPrompt),
162→        ]);
163→
164→        $fullReply = '';
165→        $buffer = '';
166→        $rawResponse = '';
167→
168→        $ch = curl_init($difyUrl);
169→        curl_setopt_array($ch, [
170→            CURLOPT_POST => true,
171→            CURLOPT_POSTFIELDS => $payload,
172→            CURLOPT_HTTPHEADER => ['Content-Type: application/json', 'Authorization: Bearer '.$difyKey],
173→            CURLOPT_RETURNTRANSFER => false,
174→            CURLOPT_TIMEOUT => 300,
175→            CURLOPT_WRITEFUNCTION => function ($curl, $data) use (&$fullReply, &$buffer, &$rawResponse, $onChunk) {
176→                $rawResponse .= $data;
177→                $buffer .= $data;
178→
179→                while (($pos = strpos($buffer, "\n")) !== false) {
180→                    $line = rtrim(substr($buffer, 0, $pos), "\r");
181→                    $buffer = substr($buffer, $pos + 1);
182→
183→                    if (!str_starts_with($line, 'data: ')) {
184→                        continue;
185→                    }
186→
187→                    $decoded = json_decode(substr($line, 6), true);
188→                    if (!is_array($decoded)) {
189→                        continue;
190→                    }
191→
192→                    $event = $decoded['event'] ?? '';
193→
194→                    // Chatbot 模式：answer 字段
195→                    if ($event === 'message') {
196→                        $chunk = $decoded['answer'] ?? '';
197→                        if ($chunk !== '') {
198→                            $fullReply .= $chunk;
199→                            $onChunk($chunk);
200→                        }
201→                        // Workflow 流式模式：data.text 字段
202→                    } elseif ($event === 'text_chunk') {
203→                        $chunk = $decoded['data']['text'] ?? '';
204→                        if ($chunk !== '') {
205→                            $fullReply .= $chunk;
206→                            $onChunk($chunk);
207→                        }
208→                        // Workflow 非流式兜底：outputs.answer
209→                    } elseif ($event === 'workflow_finished') {
210→                        if (empty($fullReply)) {
211→                            $answer = $decoded['data']['outputs']['answer'] ?? '';
212→                            if ($answer !== '') {
213→                                $fullReply = $answer;
214→                                $onChunk($answer);
215→                            }
216→                        }
217→                    } elseif ($event === 'error') {
218→                        Log::error('[lbl][0416-AI日报][AiAnalysis][Dify] error event', ['event' => $decoded]);
219→                    }
220→                }
221→
222→                return strlen($data);
223→            },
224→        ]);
225→
226→        curl_exec($ch);
227→        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
228→        $curlError = curl_error($ch);
229→        curl_close($ch);
230→
231→        if ($curlError) {
232→            Log::error('[lbl][0416-AI日报][AiAnalysis][Dify] streaming curl error', ['error' => $curlError]);
233→        }
234→
235→        // Dify 返回数据但未解析出回复，尝试解析 JSON 错误
236→        if (empty($fullReply) && !empty($rawResponse)) {
237→            Log::error('[lbl][0416-AI日报][AiAnalysis][Dify] empty reply', ['raw' => mb_substr($rawResponse, 0, 1000)]);
238→            $jsonErr = json_decode($rawResponse, true);
239→            if (is_array($jsonErr) && isset($jsonErr['message'])) {
240→                Log::error('[lbl][0416-AI日报][AiAnalysis][Dify] api error', ['message' => $jsonErr['message']]);
241→            }
242→        }
243→
244→        Log::info('[lbl][0416-AI日报][AiAnalysis][Dify] streaming done', [
245→            'http_code' => $httpCode,
246→            'reply_len' => mb_strlen($fullReply),
247→        ]);
248→
249→        return $fullReply;
250→    }
