256→    /**
257→     * Vertex AI Blocking 模式（OpenAI 兼容格式）。
258→     */
259→    private function analyzeVertexAi(string $content, string $systemPrompt): string
260→    {
261→        [$endpoint, $model] = $this->getVertexAiEndpoint();
262→
263→        Log::info('[lbl][0416-AI日报][AiAnalysis][VertexAI][CALL] blocking 请求 Vertex AI', [
264→            'url' => $endpoint,
265→            'model' => $model,
266→            'content_len' => mb_strlen($content),
267→            'prompt_len' => mb_strlen($systemPrompt),
268→        ]);
269→
270→        $payload = json_encode([
271→            'model' => $model,
272→            'messages' => [
273→                ['role' => 'system', 'content' => $systemPrompt],
274→                ['role' => 'user', 'content' => $content],
275→            ],
276→            'stream' => false,
277→        ], JSON_UNESCAPED_UNICODE);
278→
279→        $maxRetries = 3;
280→        $retryDelays = [5, 10, 20]; // 递增间隔（秒）
281→
282→        for ($attempt = 1; $attempt <= $maxRetries; ++$attempt) {
283→            $accessToken = $this->getAccessToken();
284→            if (empty($accessToken)) {
285→                Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] failed to get access token', ['attempt' => $attempt]);
286→                if ($attempt < $maxRetries) {
287→                    sleep($retryDelays[$attempt - 1]);
288→                }
289→                continue;
290→            }
291→
292→            $startTime = microtime(true);
293→            $ch = curl_init($endpoint);
294→            curl_setopt_array($ch, [
295→                CURLOPT_POST => true,
296→                CURLOPT_POSTFIELDS => $payload,
297→                CURLOPT_HTTPHEADER => ['Content-Type: application/json', 'Authorization: Bearer '.$accessToken],
298→                CURLOPT_RETURNTRANSFER => true,
299→                CURLOPT_TIMEOUT => 120,
300→                CURLOPT_CONNECTTIMEOUT => 10,
301→            ]);
302→
303→            $response = curl_exec($ch);
304→            $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
305→            $curlErrNo = curl_errno($ch);
306→            $curlError = $response === false ? curl_error($ch) : '';
307→            $elapsed = round(microtime(true) - $startTime, 2);
308→            curl_close($ch);
309→
310→            // curl 网络/超时错误 → 可重试
311→            if ($curlError) {
312→                Log::warning('[lbl][0416-AI日报][AiAnalysis][VertexAI] curl error, attempt {attempt}/{max}', [
313→                    'attempt' => $attempt, 'max' => $maxRetries,
314→                    'error' => $curlError, 'curl_errno' => $curlErrNo, 'elapsed' => $elapsed,
315→                ]);
316→                if ($attempt < $maxRetries) {
317→                    sleep($retryDelays[$attempt - 1]);
318→                }
319→                continue;
320→            }
321→
322→            // 5xx 服务端错误 → 可重试
323→            if ($httpCode >= 500) {
324→                Log::warning('[lbl][0416-AI日报][AiAnalysis][VertexAI] server error, attempt {attempt}/{max}', [
325→                    'attempt' => $attempt, 'max' => $maxRetries,
326→                    'http_code' => $httpCode, 'elapsed' => $elapsed,
327→                    'raw' => mb_substr($response, 0, 500),
328→                ]);
329→                if ($attempt < $maxRetries) {
330→                    sleep($retryDelays[$attempt - 1]);
331→                }
332→                continue;
333→            }
334→
335→            // 4xx 客户端错误 → 不重试
336→            if ($httpCode >= 400) {
337→                Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] client error, not retrying', [
338→                    'http_code' => $httpCode, 'elapsed' => $elapsed,
339→                    'raw' => mb_substr($response, 0, 1000),
340→                ]);
341→                return '';
342→            }
343→
344→            $result = json_decode($response, true);
345→            if (!is_array($result)) {
346→                Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] invalid response', [
347→                    'http_code' => $httpCode, 'elapsed' => $elapsed,
348→                    'raw' => mb_substr($response, 0, 1000),
349→                ]);
350→                return '';
351→            }
352→
353→            $answer = Arr::get($result, 'choices.0.message.content', '');
354→            Log::info('[lbl][0416-AI日报][AiAnalysis][VertexAI] blocking done', [
355→                'http_code' => $httpCode, 'answer_len' => mb_strlen($answer),
356→                'elapsed' => $elapsed, 'attempt' => $attempt,
357→            ]);
358→
359→            return $answer;
360→        }
361→
362→        Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] all {max} attempts failed', ['max' => $maxRetries]);
363→        return '';
364→    }
