366→    /**
367→     * Vertex AI Streaming 模式（OpenAI 兼容格式）。
368→     */
369→    private function analyzeStreamVertexAi(string $content, string $systemPrompt, callable $onChunk, array $history = []): string
370→    {
371→        $accessToken = $this->getAccessToken();
372→        if (empty($accessToken)) {
373→            Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] failed to get access token');
374→            return '';
375→        }
376→
377→        [$endpoint, $model] = $this->getVertexAiEndpoint();
378→
379→        Log::info('[lbl][0416-AI日报][AiAnalysis][VertexAI][CALL] streaming 请求 Vertex AI', [
380→            'url' => $endpoint,
381→            'model' => $model,
382→            'content_len' => mb_strlen($content),
383→            'prompt_len' => mb_strlen($systemPrompt),
384→            'history_count' => count($history),
385→        ]);
386→
387→        $messages = [['role' => 'system', 'content' => $systemPrompt]];
388→        foreach ($history as $msg) {
389→            $messages[] = ['role' => $msg['role'], 'content' => $msg['content']];
390→        }
391→        if (!empty($content)) {
392→            $messages[] = ['role' => 'user', 'content' => $content];
393→        }
394→
395→        $payload = json_encode([
396→            'model' => $model,
397→            'messages' => $messages,
398→            'stream' => true,
399→        ], JSON_UNESCAPED_UNICODE);
400→
401→        $fullReply = '';
402→        $buffer = '';
403→        $rawResponse = '';
404→
405→        $ch = curl_init($endpoint);
406→        curl_setopt_array($ch, [
407→            CURLOPT_POST => true,
408→            CURLOPT_POSTFIELDS => $payload,
409→            CURLOPT_HTTPHEADER => ['Content-Type: application/json', 'Authorization: Bearer '.$accessToken],
410→            CURLOPT_RETURNTRANSFER => false,
411→            CURLOPT_TIMEOUT => 300,
412→            CURLOPT_WRITEFUNCTION => function ($curl, $data) use (&$fullReply, &$buffer, &$rawResponse, $onChunk) {
413→                $rawResponse .= $data;
414→                $buffer .= $data;
415→
416→                while (($pos = strpos($buffer, "\n")) !== false) {
417→                    $line = rtrim(substr($buffer, 0, $pos), "\r");
418→                    $buffer = substr($buffer, $pos + 1);
419→
420→                    if (!str_starts_with($line, 'data: ')) {
421→                        continue;
422→                    }
423→
424→                    $jsonStr = substr($line, 6);
425→                    if ($jsonStr === '[DONE]') {
426→                        continue;
427→                    }
428→
429→                    $decoded = json_decode($jsonStr, true);
430→                    if (!is_array($decoded)) {
431→                        continue;
432→                    }
433→
434→                    $chunk = Arr::get($decoded, 'choices.0.delta.content', '');
435→                    if ($chunk !== '') {
436→                        $fullReply .= $chunk;
437→                        $onChunk($chunk);
438→                    }
439→                }
440→
441→                return strlen($data);
442→            },
443→        ]);
444→
445→        curl_exec($ch);
446→        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
447→        $curlErrNo = curl_errno($ch);
448→        $curlError = curl_error($ch);
449→        curl_close($ch);
450→
451→        if ($curlError) {
452→            Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] streaming curl error', [
453→                'error' => $curlError, 'curl_errno' => $curlErrNo,
454→            ]);
455→        }
456→
457→        // 空回复检查：跟 Dify 路径对齐，尝试从原始响应解析错误信息
458→        if (empty($fullReply) && !empty($rawResponse)) {
459→            Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] streaming empty reply', [
460→                'http_code' => $httpCode,
461→                'raw' => mb_substr($rawResponse, 0, 1000),
462→            ]);
463→            $jsonErr = json_decode($rawResponse, true);
464→            if (is_array($jsonErr) && isset($jsonErr['error'])) {
465→                Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] api error in stream', [
466→                    'error' => $jsonErr['error'],
467→                ]);
468→            }
469→        }
470→
471→        Log::info('[lbl][0416-AI日报][AiAnalysis][VertexAI] streaming done', [
472→            'http_code' => $httpCode,
473→            'reply_len' => mb_strlen($fullReply),
474→            'raw_response_preview' => mb_substr($rawResponse, 0, 500),
475→        ]);
476→
477→        return $fullReply;
478→    }
