493→    /**
494→     * 通过 GCE Metadata Server 获取 Service Account 的 access token。
495→     */
496→    private function getAccessToken(): string
497→    {
498→        $url = 'http://metadata.google.internal/computeMetadata/v1/instance/service-accounts/default/token';
499→        $context = stream_context_create([
500→            'http' => [
501→                'header' => 'Metadata-Flavor: Google',
502→                'timeout' => 5,
503→            ],
504→        ]);
505→
506→        $response = @file_get_contents($url, false, $context);
507→        if ($response === false) {
508→            Log::error('[lbl][0416-AI日报][AiAnalysis] failed to get access token from metadata server');
509→            return '';
510→        }
511→
512→        $data = json_decode($response, true);
513→        return $data['access_token'] ?? '';
514→    }
515→}
